DECLARE @SpecialGroupId SMALLINT = -1; DECLARE @PersonId INT = -1; DECLARE @PlanYear SMALLINT = 2024;
-- =========================================================================================================================================== -- Calc Analysis Between PlanYears -- Test Case: Compare elections between planyears -- ===========================================================================================================================================
----------------------------------------------------------------------------------- -- Parameters -----------------------------------------------------------------------------------
DECLARE @PlanYear1 SMALLINT = @PlanYear - 1; DECLARE @PlanYear2 SMALLINT = @PlanYear;
----------------------------------------------------------------------------------- SET TRANSACTION ISOLATION LEVEL READ UNCOMMITTED;
----------------------------------------------------------------------------------- -- 0 - Select employees for AE ----------------------------------------------------------------------------------- DROP TABLE IF EXISTS #group
SELECT TOP 1 c1.PersonId, PlanYear1 = c1.PlanYear, CalcId1 = c1.CalcId, EventCode1 = c1.EventCode, PlanYear2 = c2.PlanYear, CalcId2 = c2.CalcId, EventCode2 = c2.EventCode INTO #group FROM dbo.hw_calcmaster c1 WITH (NOLOCK) JOIN dbo.hw_calcmaster c2 WITH (NOLOCK) ON c1.PersonId = c2.PersonId AND c1.PlanYear = @PlanYear1 AND c2.PlanYear = @PlanYear2 AND c1.RecordStatus = 'A' AND c2.RecordStatus = 'A'
WHERE
dbo.IsInternalTest(c1.PersonId) = 0 AND ( @SpecialGroupId = -1 OR c1.PersonId IN ( SELECT PersonId FROM cdm_person_select_ids (NOLOCK) WHERE GroupId = @SpecialGroupId ) ) AND ( @PersonId = -1 OR c1.PersonId = @PersonId) -----------------------------------------------------------------------------------
----------------------------------------------------------------------------------- ----------------------------------------------------------------------------------- -- 1 - Gather two data sets for employee comparison ----------------------------------------------------------------------------------- ;WITH CTE_Election_1 AS ( SELECT e.* ,l.CovAmt ,l.CostEffectiveDate ,EventCode1 = c.EventCode1 FROM hw_election_log e(NOLOCK) INNER JOIN #group c(NOLOCK) ON e.PersonId = c.PersonId AND e.PlanYear = c.PlanYear1 AND e.CalcId = c.CalcId1 AND e.RecordStatus = 'A' LEFT JOIN hw_eligibility l(NOLOCK) ON l.PersonId = e.PersonId AND l.PlanYear = e.PlanYear AND l.CalcId = e.CalcId AND l.BenId = e.BenId AND l.OptionId = e.OptionId AND l.TierId = e.TierId ) ,CTE_Election_2 AS ( SELECT e.* ,l.CovAmt ,l.CostEffectiveDate ,EventCode2 = c.EventCode2 FROM hw_election_log e(NOLOCK) INNER JOIN #group c(NOLOCK) ON e.PersonId = c.PersonId AND e.PlanYear = c.PlanYear2 AND e.CalcId = c.CalcId2 AND e.RecordStatus = 'A' LEFT JOIN hw_eligibility l(NOLOCK) ON l.PersonId = e.PersonId AND l.PlanYear = e.PlanYear AND l.CalcId = e.CalcId AND l.BenId = e.BenId AND l.OptionId = e.OptionId AND l.TierId = e.TierId ) --------------------------------------------------------------------------------------------------------------------- -------------------------------------------------------------------------------------------------------------------- -- ANALYSIS - Compare the two data sets and identify any differences -------------------------------------------------------------------------------------------------------------------- SELECT * FROM ( SELECT PersonId = ISNULL(e1.PersonId, e2.PersonId) ,PlanYear = ISNULL(e1.PlanYear, e2.PlanYear) ,BenId = ISNULL(e1.BenId, e2.BenId) ,OptionId1 = e1.OptionId ,OptionId2 = e2.OptionId ,TierId1 = e1.TierId ,TierId2 = e2.TierId ,EffectiveDate1 = e1.EffectiveDate ,EffectiveDate2 = e2.EffectiveDate ,EoiStatus1 = e1.EoiStatus ,EoiStatus2 = e2.EoiStatus ,CoverageEffectiveDate1 = e1.CoverageEffectiveDate ,CoverageEffectiveDate2 = e2.CoverageEffectiveDate ,CostEffectiveDate1 = e1.CostEffectiveDate ,CostEffectiveDate2 = e2.CostEffectiveDate ,EoiPend1 = e1.EoiPend ,EoiPend2 = e2.EoiPend ,Termed1 = e1.Termed ,Termed2 = e2.Termed ,TermDate1 = e1.TermDate ,TermDate2 = e2.TermDate ,CovAmt1 = e1.CovAmt ,CovAmt2 = e2.CovAmt ,EventCode1 = e1.EventCode1 ,EventCode2 = e2.EventCode2 ,ElectedAmount1 = e1.ElectedAmount ,ElectedAmount2 = e2.ElectedAmount ,Thumbprint1 = CONVERT(VARCHAR(255), HASHBYTES('SHA1', CONCAT ( e1.BenId ,e1.OptionId ,e1.TierId ,e1.TermDate ,e1.CoverageEffectiveDate ,e1.CostEffectiveDate ,e1.EffectiveDate ,e1.EoiStatus ,e1.EoiPend ,e1.ElectedAmount ,e1.Termed ,e1.CovAmt ,e1.EventCode1 )), 2) ,Thumbprint2 = CONVERT(VARCHAR(255), HASHBYTES('SHA1', CONCAT ( e2.BenId ,e2.OptionId ,e2.TierId ,e2.TermDate ,e2.CoverageEffectiveDate ,e2.CostEffectiveDate ,e2.EffectiveDate ,e2.EoiStatus ,e2.EoiPend ,e2.ElectedAmount ,e2.Termed ,e2.CovAmt ,e2.EventCode2 )), 2) ,Result = '===>>' ,BenefitAnalysis = CASE WHEN e1.BenId IS NULL THEN 'GAIN' WHEN e2.BenId IS NULL AND ISNULL(e1.Termed, 0) = 0 THEN 'LOSS' ELSE 'NO CHANGE' END ,OptionAnalysis = CASE WHEN e1.OptionId IS NULL OR e2.OptionId IS NULL THEN 'NO COMPARE' WHEN e1.PlanYear != e2.PlanYear AND e1.BenId IN ( 11 ,12 ) AND e1.OptionId > 0 AND ISNULL(e1.Termed, 0) = 0 AND e2.Source = 'D' AND e2.OptionId > 0 AND ISNULL(e2.Termed, 0) = 0 THEN 'SHOULD DEFAULT TO ZERO' WHEN e1.OptionId > 0 AND ISNULL(e1.Termed, 0) = 0 AND e2.OptionId = 0 THEN 'WAIVE' WHEN e1.OptionId >= 0 AND ISNULL(e1.Termed, 0) = 0 AND e2.OptionId >= 0 AND e2.Termed = 1 THEN 'TERM' WHEN e1.OptionId = 0 AND e2.OptionId > 0 AND ISNULL(e2.Termed, 0) = 0 THEN 'GAIN' WHEN e1.OptionId > 0 AND e2.OptionId > 0 AND e1.OptionId != e2.OptionId THEN 'CHANGE' WHEN e1.OptionId = e2.OptionId THEN 'NO CHANGE' WHEN e1.OptionId > 0 AND e1.Termed = 1 AND e2.OptionId = 0 THEN 'TERM TO WAIVE' ELSE 'UNKNOWN' END ,TierAnalysis = CASE WHEN e1.TierId IS NULL OR e2.TierId IS NULL THEN 'NO COMPARE' WHEN e1.TierId > 0 AND e2.TierId = 0 THEN 'LOSS' WHEN e1.TierId = 0 AND e2.TierId > 0 THEN 'GAIN' WHEN e1.TierId > 0 AND e2.TierId > 0 AND e1.TierId != e2.TierId THEN 'CHANGE' WHEN e1.TierId = e1.TierId THEN 'NO CHANGE' ELSE 'UNKNOWN' END ,EffectiveDateAnalysis = CASE WHEN e1.EffectiveDate IS NULL OR e2.EffectiveDate IS NULL THEN 'NO COMPARE' WHEN e1.EffectiveDate != e2.EffectiveDate THEN 'CHANGE' WHEN e1.EffectiveDate = e2.EffectiveDate THEN 'NO CHANGE' ELSE 'UNKNOWN' END ,CoverageEffectiveDateAnalysis = CASE WHEN e1.CoverageEffectiveDate IS NULL OR e2.CoverageEffectiveDate IS NULL THEN 'NO COMPARE' WHEN e1.CoverageEffectiveDate != e2.CoverageEffectiveDate THEN 'CHANGE' WHEN e1.CoverageEffectiveDate = e2.CoverageEffectiveDate THEN 'NO CHANGE' ELSE 'UNKNOWN' END ,CostEffectiveDateAnalysis = CASE WHEN e1.CostEffectiveDate IS NULL OR e2.CostEffectiveDate IS NULL THEN 'NO COMPARE' WHEN e1.CostEffectiveDate != e2.CostEffectiveDate THEN 'CHANGE' WHEN e1.CostEffectiveDate = e2.CostEffectiveDate THEN 'NO CHANGE' ELSE 'UNKNOWN' END ,TermDateAnalysis = CASE WHEN e1.TermDate IS NULL OR e2.TermDate IS NULL THEN 'NO COMPARE' WHEN e1.TermDate != e2.TermDate THEN 'CHANGE' WHEN e1.TermDate = e2.TermDate THEN 'NO CHANGE' ELSE 'UNKNOWN' END , -- Add EoiStatus, EoiPend, and EoiTier EOIPendAnalysis = CASE WHEN e1.EoiStatus IS NULL OR e2.EoiStatus IS NULL THEN 'NO COMPARE' WHEN e2.EoiPend != 99 AND ISNULL(e2.Termed, 0) = 0 THEN CASE WHEN ISNULL(e1.EoiPend, 0) < ISNULL(e2.EoiPend, 0) THEN 'OPTION INCREASE' WHEN ISNULL(e1.EoiPendTier, 0) < ISNULL(e2.EoiPendTier, 0) THEN 'TIER INCREASE' WHEN ISNULL(e1.EoiPend, 0) > ISNULL(e2.EoiPend, 0) THEN 'OPTION DECREASE' WHEN ISNULL(e1.EoiPendTier, 0) > ISNULL(e2.EoiPendTier, 0) THEN 'TIER DECREASE' ELSE CASE WHEN e1.EoiStatus != e2.EoiStatus THEN 'EOI Status CHANGE' WHEN ISNULL(e1.EoiPend, 0) = ISNULL(e2.EoiPend, 0) THEN 'NO CHANGE' END END ELSE 'NO CHANGE' --'UNKNOWN' END ,CovAmtAnalysis = CASE WHEN e1.CovAmt IS NULL OR e2.CovAmt IS NULL THEN 'NO COMPARE' WHEN e1.CovAmt < e2.CovAmt AND ISNULL(e2.Termed, 0) = 0 THEN 'INCREASE' WHEN e1.CovAmt > e2.CovAmt AND ISNULL(e2.Termed, 0) = 0 THEN 'DECREASE' WHEN e1.CovAmt = e2.CovAmt THEN 'NO CHANGE' ELSE 'UNKNOWN' END ,ElectedAmountAnalysis = CASE WHEN e1.ElectedAmount IS NULL OR e2.ElectedAmount IS NULL THEN 'NO COMPARE' WHEN e1.ElectedAmount < e2.ElectedAmount AND ISNULL(e2.Termed, 0) = 0 THEN 'INCREASE' WHEN e1.ElectedAmount > e2.ElectedAmount AND ISNULL(e2.Termed, 0) = 0 THEN 'DECREASE' WHEN e1.ElectedAmount = e2.ElectedAmount THEN 'NO CHANGE' ELSE 'UNKNOWN' END FROM CTE_Election_1 e1 FULL JOIN CTE_Election_2 e2 ON e1.PersonId = e2.PersonId AND e1.BenId = e2.BenId ) t WHERE (Thumbprint1 != Thumbprint2 OR @PersonId != -1) ------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------ ORDER BY 1 ,2 ,3 ,4;
GO DECLARE @SpecialGroupId SMALLINT = -1; DECLARE @PersonId INT = -1; DECLARE @PlanYear SMALLINT = 2024;
-- =========================================================================================================================================== -- Calc Analysis Between PlanYears -- Test Case: Compare elections between planyears -- ===========================================================================================================================================
----------------------------------------------------------------------------------- -- Parameters -----------------------------------------------------------------------------------
DECLARE @PlanYear1 SMALLINT = @PlanYear - 1; DECLARE @PlanYear2 SMALLINT = @PlanYear;
----------------------------------------------------------------------------------- SET TRANSACTION ISOLATION LEVEL READ UNCOMMITTED;
----------------------------------------------------------------------------------- -- 0 - Select employees for AE ----------------------------------------------------------------------------------- DROP TABLE IF EXISTS #group
SELECT TOP 1 c1.PersonId, PlanYear1 = c1.PlanYear, CalcId1 = c1.CalcId, EventCode1 = c1.EventCode, PlanYear2 = c2.PlanYear, CalcId2 = c2.CalcId, EventCode2 = c2.EventCode INTO #group FROM dbo.hw_calcmaster c1 WITH (NOLOCK) JOIN dbo.hw_calcmaster c2 WITH (NOLOCK) ON c1.PersonId = c2.PersonId AND c1.PlanYear = @PlanYear1 AND c2.PlanYear = @PlanYear2 AND c1.RecordStatus = 'A' AND c2.RecordStatus = 'A'
WHERE
dbo.IsInternalTest(c1.PersonId) = 0 AND ( @SpecialGroupId = -1 OR c1.PersonId IN ( SELECT PersonId FROM cdm_person_select_ids (NOLOCK) WHERE GroupId = @SpecialGroupId ) ) AND ( @PersonId = -1 OR c1.PersonId = @PersonId) -----------------------------------------------------------------------------------
----------------------------------------------------------------------------------- ----------------------------------------------------------------------------------- -- 1 - Gather two data sets for dependent comparison ----------------------------------------------------------------------------------- ;WITH CTE_Election_1 AS ( SELECT e.* ,EventCode1 = c.EventCode1 FROM hw_dependent_election_log e(NOLOCK) INNER JOIN #group c(NOLOCK) ON e.PersonId = c.PersonId AND e.PlanYear = c.PlanYear1 AND e.CalcId = c.CalcId1 AND e.RecordStatus = 'A' ) ,CTE_Election_2 AS ( SELECT e.* ,EventCode2 = c.EventCode2 FROM hw_dependent_election_log e(NOLOCK) INNER JOIN #group c(NOLOCK) ON e.PersonId = c.PersonId AND e.PlanYear = c.PlanYear2 AND e.CalcId = c.CalcId2 AND e.RecordStatus = 'A' ) --------------------------------------------------------------------------------------------------------------------- -------------------------------------------------------------------------------------------------------------------- -- ANALYSIS - Compare the two data sets and identify any differences -------------------------------------------------------------------------------------------------------------------- SELECT * FROM ( SELECT PersonId = ISNULL(e1.PersonId, e2.PersonId) ,DepNum = ISNULL(e1.DepNum, e2.DepNum) ,PlanYear = ISNULL(e1.PlanYear, e2.PlanYear) ,BenId = ISNULL(e1.BenId, e2.BenId) ,OptionId1 = e1.OptionId ,EffectiveDate1 = e1.EffectiveDate ,CoverageEffectiveDate1 = e1.CoverageEffectiveDate ,Termed1 = e1.Termed ,TermDate1 = e1.TermDate ,EventCode1 = e1.EventCode1 ,Thumbprint1 = CONVERT(VARCHAR(255), HASHBYTES('SHA1', CONCAT ( e1.BenId ,e1.OptionId ,e1.EffectiveDate ,e1.Termed ,e1.TermDate ,e1.CoverageEffectiveDate ,e1.IsPended ,e1.EventCode1 )), 2) ,Transition = '===>' ,OptionId2 = e2.OptionId ,EffectiveDate2 = e2.EffectiveDate ,CoverageEffectiveDate2 = e2.CoverageEffectiveDate ,Termed2 = e2.Termed ,TermDate2 = e2.TermDate ,EventCode2 = e2.EventCode2 ,Thumbprint2 = CONVERT(VARCHAR(255), HASHBYTES('SHA1', CONCAT ( e2.BenId ,e2.OptionId ,e2.EffectiveDate ,e2.Termed ,e2.TermDate ,e2.CoverageEffectiveDate ,e2.IsPended ,e2.EventCode2 )), 2) ,Result = '===>>' ,BenefitAnalysis = CASE WHEN e1.BenId IS NULL THEN 'GAIN' WHEN e2.BenId IS NULL AND ISNULL(e1.Termed, 0) = 0 THEN 'LOSS' ELSE 'NO CHANGE' END ,OptionAnalysis = CASE WHEN e1.OptionId IS NULL OR e2.OptionId IS NULL THEN 'NO COMPARE' WHEN e1.OptionId > 0 AND ISNULL(e1.Termed, 0) = 0 AND e2.OptionId = 0 THEN 'WAIVE' WHEN e1.OptionId >= 0 AND ISNULL(e1.Termed, 0) = 0 AND e2.OptionId >= 0 AND e2.Termed = 1 THEN 'TERM' WHEN e1.OptionId = 0 AND e2.OptionId > 0 AND ISNULL(e2.Termed, 0) = 0 THEN 'GAIN' WHEN e1.OptionId > 0 AND e2.OptionId > 0 AND e1.OptionId != e2.OptionId THEN 'CHANGE' WHEN e1.OptionId = e2.OptionId THEN 'NO CHANGE' WHEN e1.OptionId > 0 AND e1.Termed = 1 AND e2.OptionId = 0 THEN 'TERM TO WAIVE' ELSE 'UNKNOWN' END ,EffectiveDateAnalysis = CASE WHEN e1.EffectiveDate IS NULL OR e2.EffectiveDate IS NULL THEN 'NO COMPARE' WHEN e1.EffectiveDate != e2.EffectiveDate THEN 'CHANGE' WHEN e1.EffectiveDate = e2.EffectiveDate THEN 'NO CHANGE' ELSE 'UNKNOWN' END ,CoverageEffectiveDateAnalysis = CASE WHEN e1.CoverageEffectiveDate IS NULL OR e2.CoverageEffectiveDate IS NULL THEN 'NO COMPARE' WHEN e1.CoverageEffectiveDate != e2.CoverageEffectiveDate THEN 'CHANGE' WHEN e1.CoverageEffectiveDate = e2.CoverageEffectiveDate THEN 'NO CHANGE' ELSE 'UNKNOWN' END ,TermDateAnalysis = CASE WHEN e1.TermDate IS NULL OR e2.TermDate IS NULL THEN 'NO COMPARE' WHEN e1.TermDate != e2.TermDate THEN 'CHANGE' WHEN e1.TermDate = e2.TermDate THEN 'NO CHANGE' ELSE 'UNKNOWN' END ,IsPendedAnalysis = CASE WHEN e1.IsPended IS NULL OR e2.IsPended IS NULL THEN 'NO COMPARE' WHEN e1.IsPended != e2.IsPended THEN 'CHANGE' WHEN e1.IsPended = e2.IsPended THEN 'NO CHANGE' ELSE 'UNKNOWN' END FROM CTE_Election_1 e1 FULL JOIN CTE_Election_2 e2 ON e1.PersonId = e2.PersonId AND e1.DepNum = e2.DepNum AND e1.BenId = e2.BenId ) t WHERE (Thumbprint1 != Thumbprint2 OR @PersonId != -1) ------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------ ORDER BY 1 ,2 ,3 ,4;
GO DECLARE @SpecialGroupId SMALLINT = -1; DECLARE @PersonId INT = -1; DECLARE @PlanYear SMALLINT = 2024;
-- =========================================================================================================================================== -- Calc Analysis Between PlanYears -- Test Case: Compare elections between planyears -- ===========================================================================================================================================
----------------------------------------------------------------------------------- -- Parameters -----------------------------------------------------------------------------------
DECLARE @PlanYear1 SMALLINT = @PlanYear - 1; DECLARE @PlanYear2 SMALLINT = @PlanYear;
----------------------------------------------------------------------------------- SET TRANSACTION ISOLATION LEVEL READ UNCOMMITTED;
----------------------------------------------------------------------------------- -- 0 - Select employees for AE ----------------------------------------------------------------------------------- DROP TABLE IF EXISTS #group
SELECT TOP 1 c1.PersonId, PlanYear1 = c1.PlanYear, CalcId1 = c1.CalcId, EventCode1 = c1.EventCode, PlanYear2 = c2.PlanYear, CalcId2 = c2.CalcId, EventCode2 = c2.EventCode INTO #group FROM dbo.hw_calcmaster c1 WITH (NOLOCK) JOIN dbo.hw_calcmaster c2 WITH (NOLOCK) ON c1.PersonId = c2.PersonId AND c1.PlanYear = @PlanYear1 AND c2.PlanYear = @PlanYear2 AND c1.RecordStatus = 'A' AND c2.RecordStatus = 'A'
WHERE
dbo.IsInternalTest(c1.PersonId) = 0 AND ( @SpecialGroupId = -1 OR c1.PersonId IN ( SELECT PersonId FROM cdm_person_select_ids (NOLOCK) WHERE GroupId = @SpecialGroupId ) ) AND ( @PersonId = -1 OR c1.PersonId = @PersonId) -----------------------------------------------------------------------------------
----------------------------------------------------------------------------------- -- 1 - Gather two data sets for employee comparison ----------------------------------------------------------------------------------- ;WITH CTE_Election_1 AS ( SELECT e.* ,EventCode1 = c.EventCode1 FROM hw_calculated_option_tier e(NOLOCK) INNER JOIN #group c(NOLOCK) ON e.PersonId = c.PersonId AND e.PlanYear = c.PlanYear1 AND e.CalcId = c.CalcId1 AND e.RecordStatus = 'A' ) ,CTE_Election_2 AS ( SELECT e.* ,EventCode2 = c.EventCode2 FROM hw_calculated_option_tier e(NOLOCK) INNER JOIN #group c(NOLOCK) ON e.PersonId = c.PersonId AND e.PlanYear = c.PlanYear2 AND e.CalcId = c.CalcId2 AND e.RecordStatus = 'A' ) --------------------------------------------------------------------------------------------------------------------- -------------------------------------------------------------------------------------------------------------------- -- ANALYSIS - Compare the two data sets and identify any differences -------------------------------------------------------------------------------------------------------------------- SELECT * FROM ( SELECT PersonId = ISNULL(e1.PersonId, e2.PersonId) ,PlanYear = ISNULL(e1.PlanYear, e2.PlanYear) ,BenId = ISNULL(e1.BenId, e2.BenId) ,OptionId1 = e1.OptionId ,OptionId2 = e2.OptionId ,TierId1 = e1.TierId ,TierId2 = e2.TierId ,EffectiveDate1 = e1.EffectiveDate ,EffectiveDate2 = e2.EffectiveDate ,HasPendedDependents1 = e1.HasPendedDependents ,DependentVerificationPendingTier2 = e2.DependentVerificationPendingTier ,Thumbprint1 = CONVERT(VARCHAR(255), HASHBYTES('SHA1', CONCAT ( e1.BenId ,e1.OptionId ,e1.TierId ,e1.EffectiveDate ,e1.HasPendedDependents ,e1.DependentVerificationPendingTier ,e1.EventCode1 )), 2) ,Thumbprint2 = CONVERT(VARCHAR(255), HASHBYTES('SHA1', CONCAT ( e2.BenId ,e2.OptionId ,e2.TierId ,e2.EffectiveDate ,e2.HasPendedDependents ,e2.DependentVerificationPendingTier ,e2.EventCode2 )), 2) ,Result = '===>>' ,BenefitAnalysis = CASE WHEN e1.BenId IS NULL THEN 'GAIN' WHEN e2.BenId IS NULL THEN 'LOSS' ELSE 'NO CHANGE' END ,OptionAnalysis = CASE WHEN e1.OptionId IS NULL OR e2.OptionId IS NULL THEN 'NO COMPARE' WHEN e1.OptionId > 0 AND e2.OptionId = 0 THEN 'WAIVE' WHEN e1.OptionId = 0 AND e2.OptionId > 0 THEN 'GAIN' WHEN e1.OptionId > 0 AND e2.OptionId > 0 AND e1.OptionId != e2.OptionId THEN 'CHANGE' WHEN e1.OptionId = e2.OptionId THEN 'NO CHANGE' ELSE 'UNKNOWN' END ,TierAnalysis = CASE WHEN e1.TierId IS NULL OR e2.TierId IS NULL THEN 'NO COMPARE' WHEN e1.TierId > 0 AND e2.TierId = 0 THEN 'LOSS' WHEN e1.TierId = 0 AND e2.TierId > 0 THEN 'GAIN' WHEN e1.TierId > 0 AND e2.TierId > 0 AND e1.TierId != e2.TierId THEN 'CHANGE' WHEN e1.TierId = e1.TierId THEN 'NO CHANGE' ELSE 'UNKNOWN' END ,EffectiveDateAnalysis = CASE WHEN e1.EffectiveDate IS NULL OR e2.EffectiveDate IS NULL THEN 'NO COMPARE' WHEN e1.EffectiveDate != e2.EffectiveDate THEN 'CHANGE' WHEN e1.EffectiveDate = e2.EffectiveDate THEN 'NO CHANGE' ELSE 'UNKNOWN' END ,HasPendedDependentsAnalysis = CASE WHEN e1.HasPendedDependents IS NULL OR e2.HasPendedDependents IS NULL THEN 'NO COMPARE' WHEN e1.HasPendedDependents != e2.HasPendedDependents THEN 'CHANGE' WHEN e1.HasPendedDependents = e2.HasPendedDependents THEN 'NO CHANGE' ELSE 'UNKNOWN' END ,DependentVerificationPendingTierAnalysis = CASE WHEN e1.TierId IS NULL OR e2.TierId IS NULL THEN 'NO COMPARE' WHEN e1.TierId > 0 AND e2.TierId = 0 THEN 'LOSS' WHEN e1.TierId = 0 AND e2.TierId > 0 THEN 'GAIN' WHEN e1.TierId > 0 AND e2.TierId > 0 AND e1.TierId != e2.TierId THEN 'CHANGE' WHEN e1.TierId = e1.TierId THEN 'NO CHANGE' ELSE 'UNKNOWN' END FROM CTE_Election_1 e1 FULL JOIN CTE_Election_2 e2 ON e1.PersonId = e2.PersonId AND e1.BenId = e2.BenId ) t WHERE (Thumbprint1 != Thumbprint2 OR @PersonId != -1) ------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------ ORDER BY 1 ,2 ,3 ,4;

DECLARE @GroupId SMALLINT = 2;
DECLARE @PlanYear SMALLINT = 2025;
DECLARE @Debug BIT = 0; DROP TABLE IF EXISTS #group
SELECT TOP 1 PersonId INTO #group FROM dbo.hw_calcmaster cm WITH (NOLOCK) WHERE cm.RecordStatus = 'A' AND cm.PlanYear = @PlanYear AND dbo.IsInternalTest(personId) = 0 AND (
) -- ------------------------------------- -- 1 - Test population ------------------------------------- IF @Debug = 1 BEGIN
DECLARE @cols NVARCHAR(MAX);
-- Get common columns between hw_calcmaster and the mapping table SELECT @cols = STRING_AGG('cm.' + QUOTENAME(c.COLUMN_NAME), ', ') WITHIN GROUP (ORDER BY c.ORDINAL_POSITION) FROM INFORMATION_SCHEMA.COLUMNS m JOIN INFORMATION_SCHEMA.COLUMNS c ON m.COLUMN_NAME = c.COLUMN_NAME WHERE m.TABLE_NAME = 'pr_group_mapping' AND c.TABLE_NAME = 'hw_calcmaster';
-- Add Type column explicitly SET @cols += ', HasOverride = IIf(ov.PersonId IS NULL, ''N'', ''Y'')'
DECLARE @sql NVARCHAR(MAX) = ' SELECT ''Negative'' AS Type, cm.PersonId, ' + @cols + ' FROM dbo.hw_calcmaster cm (NOLOCK) LEFT JOIN dbo.hw_calcmaster_override ov (NOLOCK) ON cm.PersonId = ov.PersonId AND cm.PlanYear = ov.PlanYear AND ov.GroupId = @GroupId AND ov.Enabled = 1
WHERE cm.RecordStatus = ''A'' AND cm.PlanYear = @PlanYear AND cm.GroupId = @GroupId AND dbo.IsInternalTest(cm.PersonId) = 0 AND cm.PersonId NOT IN (SELECT PersonId FROM #group)
UNION ALL
SELECT ''Fallout'' AS Type, cm.PersonId, ' + @cols + ' FROM dbo.hw_calcmaster cm (NOLOCK) LEFT JOIN dbo.hw_calcmaster_override ov (NOLOCK) ON cm.PersonId = ov.PersonId AND cm.PlanYear = ov.PlanYear AND ov.GroupId IS NOT NULL AND ov.GroupId != @GroupId AND ov.Enabled = 1
WHERE cm.RecordStatus = ''A'' AND cm.PlanYear = @PlanYear AND cm.GroupId != @GroupId AND cm.PersonId IN (SELECT PersonId FROM #group)
ORDER By PersonId ';
-- Execute the dynamic SQL EXEC sp_executesql @sql, N'@PlanYear SMALLINT, @GroupId SMALLINT', @PlanYear, @GroupId;
END
ELSE BEGIN SELECT Type = 'Target', Count = COUNT(1) FROM #group ----------------------------------------------------------------------------------------------------------------------------------------------------
UNION ALL
------------------------------------- -- 2 - Positive Test ------------------------------------- SELECT Type = 'Positive', Count = COUNT(1) FROM dbo.hw_calcmaster WITH (NOLOCK) WHERE RecordStatus = 'A' AND PlanYear = @PlanYear AND GroupId = @GroupId AND PersonId IN (SELECT PersonId FROM #group) ----------------------------------------------------------------------------------------------------------------------------------------------------
UNION ALL
-------------------- -- 3 - Negative Test -------------------- SELECT Type = 'Negative', Count = COUNT(1) FROM dbo.hw_calcmaster WITH (NOLOCK) WHERE RecordStatus = 'A' AND PlanYear = @PlanYear AND GroupId = @GroupId AND dbo.IsInternalTest(personId) = 0 AND PersonId NOT IN (SELECT PersonId FROM #group) ----------------------------------------------------------------------------------------------------------------------------------------------------
UNION ALL
------------------------------------- -- 4 - Fallout Test ------------------------------------- SELECT Type = 'Fallout', Count = COUNT(1) FROM dbo.hw_calcmaster WITH (NOLOCK) WHERE RecordStatus = 'A' AND PlanYear = @PlanYear AND GroupId != @GroupId AND PersonId IN (SELECT PersonId FROM #group) ---------------------------------------------------------------------------------------------------------------------------------------------------- END; --

DECLARE @BenId SMALLINT = 4;
DECLARE @PlanYear SMALLINT = 2025;
SET TRANSACTION ISOLATION LEVEL READ UNCOMMITTED; DECLARE @AmountThreshold DECIMAL(10, 4) = 50000.00; DECLARE @RatePer DECIMAL(10, 4) = 1000.00; DECLARE @Debug BIT = 0;
-- Declare the table variable DECLARE @AgeRates TABLE ( AgeFrom INT, AgeTo INT, Rate DECIMAL(10, 4) );
-- Insert data into the table variable INSERT INTO @AgeRates(AgeFrom, AgeTo, Rate) VALUES ( 0, 24, 0.0500), (25, 29, 0.0600), (30, 34, 0.0800), (35, 39, 0.0900), (40, 44, 0.1000), (45, 49, 0.1500), (50, 54, 0.2300), (55, 59, 0.4300), (60, 64, 0.6600), (65, 69, 1.2700), (70, 200, 2.0600);
DROP TABLE IF EXISTS #group;
SELECT TOP 1 cm.PersonId, cm.PlanYear, cm.CalcId, cm.PriceGroupId, cm.ImputedAge, elig.BenId, elig.OptionId, rate.Rate, elig.CovAmt, elig.PosTaxPrice, ExpectedImputed = CONVERT(DECIMAL(18, 4), elig.Imputed), ActualImputed = CONVERT(DECIMAL(18, 4), ((elig.CovAmt - @AmountThreshold) / @RatePer * rate.Rate) - PosTaxPrice)
INTO #group FROM hw_calcmaster cm WITH (NOLOCK) JOIN hw_eligibility elig WITH (NOLOCK) ON elig.PersonId = cm.PersonId AND elig.PlanYear = cm.PlanYear AND elig.CalcId = cm.CalcId JOIN @AgeRates rate ON cm.ImputedAge BETWEEN rate.AgeFrom AND rate.AgeTo WHERE cm.PlanYear = @PlanYear AND cm.RecordStatus = 'A' AND cm.GroupId > 0 AND dbo.IsInternalTest(cm.PersonId) = 0 AND elig.BenId = @BenId; -- IF @Debug = 1 BEGIN SELECT * FROM #group WHERE ExpectedImputed != ActualImputed; END
ELSE BEGIN ------------------------------------- -- 1 - Test population ------------------------------------- SELECT Type = 'Target', Count = COUNT(1) FROM #group ----------------------------------------------------------------------------------------------------------------------------------------------------
UNION ALL
------------------------------------- -- 2 - Positive Test ------------------------------------- SELECT Type = 'Positive', Count = COUNT(1) FROM #group WITH (NOLOCK) WHERE ExpectedImputed = ActualImputed ----------------------------------------------------------------------------------------------------------------------------------------------------
UNION ALL
------------------------------------- -- 3 - Negative Test ------------------------------------- SELECT Type = 'Negative', Count = COUNT(1) FROM #group WITH (NOLOCK) WHERE ExpectedImputed != ActualImputed ---------------------------------------------------------------------------------------------------------------------------------------------------- END;
DROP TABLE IF EXISTS #group; --

DECLARE @PriceGroupId SMALLINT = 1;
DECLARE @PlanYear SMALLINT = 2025;
DECLARE @Debug BIT = 0; DROP TABLE IF EXISTS #group
SELECT TOP 1 PersonId INTO #group FROM dbo.hw_calcmaster cm WITH (NOLOCK) WHERE cm.RecordStatus = 'A' AND cm.PlanYear = @PlanYear AND dbo.IsInternalTest(personId) = 0 AND ( ISNULL(cm.Location, '') = 'a' AND (cm.GroupId = 1) ) -- ------------------------------------- -- 1 - Test population ------------------------------------- IF @Debug = 1 BEGIN
DECLARE @cols NVARCHAR(MAX);
-- Get common columns between hw_calcmaster and the mapping table SELECT @cols = STRING_AGG('cm.' + QUOTENAME(c.COLUMN_NAME), ', ') WITHIN GROUP (ORDER BY c.ORDINAL_POSITION) FROM INFORMATION_SCHEMA.COLUMNS m JOIN INFORMATION_SCHEMA.COLUMNS c ON m.COLUMN_NAME = c.COLUMN_NAME WHERE m.TABLE_NAME = 'pr_pricegroup_mapping' AND c.TABLE_NAME = 'hw_calcmaster';
-- Add Type column explicitly SET @cols += ', HasOverride = IIf(ov.PersonId IS NULL, ''N'', ''Y'')'
DECLARE @sql NVARCHAR(MAX) = ' SELECT ''Negative'' AS Type, cm.PersonId, ' + @cols + ' FROM dbo.hw_calcmaster cm (NOLOCK) LEFT JOIN dbo.hw_calcmaster_override ov (NOLOCK) ON cm.PersonId = ov.PersonId AND cm.PlanYear = ov.PlanYear AND ov.PriceGroupId = @PriceGroupId AND ov.Enabled = 1 WHERE cm.RecordStatus = ''A'' AND cm.PlanYear = @PlanYear AND cm.PriceGroupId = @PriceGroupId AND dbo.IsInternalTest(cm.PersonId) = 0 AND cm.PersonId NOT IN (SELECT PersonId FROM #group)
UNION ALL
SELECT ''Fallout'' AS Type, cm.PersonId, ' + @cols + ' FROM dbo.hw_calcmaster cm (NOLOCK) LEFT JOIN dbo.hw_calcmaster_override ov (NOLOCK) ON cm.PersonId = ov.PersonId AND cm.PlanYear = ov.PlanYear AND ov.PriceGroupId IS NOT NULL AND ov.PriceGroupId != @PriceGroupId AND ov.Enabled = 1
WHERE cm.RecordStatus = ''A'' AND cm.PlanYear = @PlanYear AND cm.PriceGroupId != @PriceGroupId AND cm.PersonId IN (SELECT PersonId FROM #group) ORDER By PersonId ';
-- Execute the dynamic SQL EXEC sp_executesql @sql, N'@PlanYear SMALLINT, @PriceGroupId SMALLINT', @PlanYear, @PriceGroupId;
END
ELSE BEGIN SELECT Type = 'Target', Count = COUNT(1) FROM #group ----------------------------------------------------------------------------------------------------------------------------------------------------
UNION ALL
------------------------------------- -- 2 - Positive Test ------------------------------------- SELECT Type = 'Positive', Count = COUNT(1) FROM dbo.hw_calcmaster WITH (NOLOCK) WHERE RecordStatus = 'A' AND PlanYear = @PlanYear AND PriceGroupId = @PriceGroupId AND PersonId IN (SELECT PersonId FROM #group) ----------------------------------------------------------------------------------------------------------------------------------------------------
UNION ALL
-------------------- -- 3 - Negative Test -------------------- SELECT Type = 'Negative', Count = COUNT(1) FROM dbo.hw_calcmaster WITH (NOLOCK) WHERE RecordStatus = 'A' AND PlanYear = @PlanYear AND PriceGroupId = @PriceGroupId AND dbo.IsInternalTest(personId) = 0 AND PersonId NOT IN (SELECT PersonId FROM #group) ----------------------------------------------------------------------------------------------------------------------------------------------------
UNION ALL
------------------------------------- -- 4 - Fallout Test ------------------------------------- SELECT Type = 'Fallout', Count = COUNT(1) FROM dbo.hw_calcmaster WITH (NOLOCK) WHERE RecordStatus = 'A' AND PlanYear = @PlanYear AND PriceGroupId != @PriceGroupId AND PersonId IN (SELECT PersonId FROM #group) ---------------------------------------------------------------------------------------------------------------------------------------------------- END; --
